// Fallback: generate initials-based icon
function getFallbackColor(name: string): string {
  const colors = ["#6366f1", "#8b5cf6", "#ec4899", "#f43f5e", "#f97316", "#eab308", "#22c55e", "#14b8a6", "#06b6d4", "#3b82f6"];
  let hash = 0;
  for (let i = 0; i < name.length; i++) hash = name.charCodeAt(i) + ((hash << 5) - hash);
  return colors[Math.abs(hash) % colors.length];
}

interface TechIconProps {
  name: string;
  size?: "sm" | "md" | "lg";
  showLabel?: boolean;
  className?: string;
}

const sizeMap = {
  sm: { icon: 16, container: 28, text: "text-[10px]" },
  md: { icon: 20, container: 36, text: "text-xs" },
  lg: { icon: 24, container: 44, text: "text-sm" },
};

export function TechIcon({ name, size = "md", showLabel = true, className }: TechIconProps) {
  const tech = techIcons[name];
  const s = sizeMap[size];

  return (
    <div className={cn("inline-flex items-center gap-2", className)}>
      <div
        className="flex items-center justify-center rounded-lg bg-indigo-50 dark:bg-indigo-500/10 shrink-0 transition-transform hover:scale-110"
        style={{ width: s.container, height: s.container }}
      >
        {tech ? (
          <svg
            viewBox={tech.viewBox || "0 0 24 24"}
            fill={tech.color}
            width={s.icon}
            height={s.icon}
            className="dark:opacity-90"
          >
            <path d={tech.path} />
          </svg>
        ) : (
          <span
            className="font-bold"
            style={{
              color: getFallbackColor(name),
              fontSize: s.icon * 0.5,
            }}
          >
            {name.slice(0, 2).toUpperCase()}
          </span>
        )}
      </div>
      {showLabel && (
        <span className={cn("font-medium text-slate-600 dark:text-slate-400", s.text)}>
          {name}
        </span>
      )}
    </div>
  );
}

// Grid layout for displaying multiple tech icons
export function TechStackGrid({
  techs,
  size = "md",
  showLabels = true,
  className,
}: {
  techs: string[];
  size?: "sm" | "md" | "lg";
  showLabels?: boolean;
  className?: string;
}) {
  return (
    <div className={cn("flex flex-wrap gap-3", className)}>
      {techs.map((tech) => (
        <TechIcon key={tech} name={tech} size={size} showLabel={showLabels} />
      ))}
    </div>
  );
}

// Compact pill layout for inline use
export function TechStackPills({
  techs,
  className,
}: {
  techs: string[];
  className?: string;
}) {
  return (
    <div className={cn("flex flex-wrap gap-1.5", className)}>
      {techs.map((tech) => {
        const t = techIcons[tech];
        return (
          <span
            key={tech}
            className="inline-flex items-center gap-1.5 rounded-full bg-indigo-50 dark:bg-indigo-500/10 px-2.5 py-1 text-xs font-medium text-indigo-700 dark:text-indigo-300 transition-colors hover:bg-indigo-100 dark:hover:bg-indigo-500/20"
          >
            {t ? (
              <svg viewBox={t.viewBox || "0 0 24 24"} fill={t.color} width={14} height={14} className="dark:opacity-90">
                <path d={t.path} />
              </svg>
            ) : (
              <span
                className="inline-block w-3.5 h-3.5 rounded-full"
                style={{ backgroundColor: getFallbackColor(tech) }}
              />
            )}
            {tech}
          </span>
        );
      })}
    </div>
  );
}

// Infinite scrolling marquee layout for tech stack
export function TechStackMarquee({
  techs,
  className,
}: {
  techs: string[];
  className?: string;
}) {
  // Double the items for seamless loop
  const items = [...techs, ...techs];

  return (
    <div className={cn("relative overflow-hidden", className)}>
      {/* Fade edges */}
      <div className="pointer-events-none absolute left-0 top-0 z-10 h-full w-16 bg-linear-to-r from-[#f8f9fc] to-transparent dark:from-[#0a0a1a]" />
      <div className="pointer-events-none absolute right-0 top-0 z-10 h-full w-16 bg-linear-to-l from-[#f8f9fc] to-transparent dark:from-[#0a0a1a]" />

      <div className="animate-marquee flex w-max gap-8 py-2">
        {items.map((tech, i) => {
          const t = techIcons[tech];
          return (
            <div
              key={`${tech}-${i}`}
              className="flex items-center gap-2.5 rounded-xl border border-indigo-100/60 dark:border-indigo-500/10 bg-white/80 dark:bg-[#111128]/80 px-4 py-2.5 shadow-sm shadow-indigo-500/3 transition-shadow hover:shadow-md hover:shadow-indigo-500/8"
            >
              <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-indigo-50 dark:bg-indigo-500/10 shrink-0">
                {t ? (
                  <svg
                    viewBox={t.viewBox || "0 0 24 24"}
                    fill={t.color}
                    width={18}
                    height={18}
                    className="dark:opacity-90"
                  >
                    <path d={t.path} />
                  </svg>
                ) : (
                  <span
                    className="font-bold text-xs"
                    style={{ color: getFallbackColor(tech) }}
                  >
                    {tech.slice(0, 2).toUpperCase()}
                  </span>
                )}
              </div>
              <span className="text-sm font-medium text-slate-700 dark:text-slate-300 whitespace-nowrap">
                {tech}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
